import{_ as d,o as e,c as r,ag as o,ah as a}from"./chunks/framework.D9bIGSBm.js";const g=JSON.parse('{"title":"CLI 与任务配置","description":"","frontmatter":{},"headers":[],"relativePath":"settings/cli.md","filePath":"settings/cli.md"}'),s={name:"settings/cli.md"};function n(l,t,h,i,p,C){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="cli-与任务配置" tabindex="-1">CLI 与任务配置 <a class="header-anchor" href="#cli-与任务配置" aria-label="Permalink to &quot;CLI 与任务配置&quot;">​</a></h1><p><strong>入口：</strong> 任务输入栏底部选择器栏（Selector Bar）</p><p>任务级配置控制单个任务使用哪套 CLI 工具、哪个模型、多深的思考深度以及多宽松的执行授权。每个任务的配置相互独立。</p><p><strong>默认值分两种情况：</strong></p><ul><li><strong>首次新建任务</strong>（从未改过任何配置）时，使用出厂默认，各项默认值见下文。</li><li><strong>修改过任意任务的配置后</strong>，整套配置会被记为「最后配置」，之后新建任务自动继承你上次的选择（v0.4.0 起）。这份记忆是应用级的，重启应用后依然有效。</li></ul><div class="tip custom-block"><p class="custom-block-title">你看到的「默认」可能是上次的配置</p><p>新建任务时各选项显示的值，往往不是出厂默认，而是你上一次使用的配置。如果发现新任务的模型或授权模式「莫名」变了，多半是上次任务中改过——直接在选择器栏改回即可。</p></div><blockquote><p>若尚未安装 Claude CLI、Codex CLI 或 OpenCode CLI，请先参阅 <a href="/docs/guide/prerequisites.html">环境准备</a>。CLI 的可执行文件路径可在 <a href="/docs/settings/general.html#cli-命令">常规设置 → CLI 命令</a> 中自定义。</p></blockquote><hr><h2 id="多-cli-架构" tabindex="-1">多 CLI 架构 <a class="header-anchor" href="#多-cli-架构" aria-label="Permalink to &quot;多 CLI 架构&quot;">​</a></h2><p>自 v0.7.0 起，应用支持多套 CLI 工具链，可在同一工作区中混合使用；自 <strong>v0.9.0</strong> 起新增第三个家族 <strong>OpenCode CLI</strong>：</p><table tabindex="0"><thead><tr><th>工具</th><th>标识</th><th>适用场景</th></tr></thead><tbody><tr><td>Claude CLI</td><td>Anthropic 图标</td><td>Claude 系列模型，支持 OAuth 直连或第三方供应商</td></tr><tr><td>Codex CLI</td><td>OpenAI 图标</td><td>Codex/GPT 系列模型，支持 OpenAI 兼容接口</td></tr><tr><td>OpenCode CLI</td><td>opencode.ai 图标</td><td>开源 CLI，复用应用已配置的 OpenAI 兼容供应商（deepseek、GLM 等），无需重复填写 Key（v0.9.0 起）</td></tr></tbody></table><p>在任务的选择器栏中点击 CLI 图标或名称，即可在各 CLI 之间切换。三个家族的模型、思考深度、权限等配置各记各的、互不串台。</p><hr><h2 id="任务级配置项" tabindex="-1">任务级配置项 <a class="header-anchor" href="#任务级配置项" aria-label="Permalink to &quot;任务级配置项&quot;">​</a></h2><p><img src="'+a+'" alt="LoongCode 主界面任务输入框下方的选择器栏，依次展示 CLI 选择、模型档位、思考深度、执行授权四组下拉控件，突出当前选中的配置值"></p><h3 id="cli-选择" tabindex="-1">CLI 选择 <a class="header-anchor" href="#cli-选择" aria-label="Permalink to &quot;CLI 选择&quot;">​</a></h3><p>选择本任务使用的工具链：<strong>Claude CLI</strong>、<strong>Codex CLI</strong> 或 <strong>OpenCode CLI</strong>。选择后，下方的模型、思考深度、执行授权选项会随之切换为对应工具链的选项。</p><hr><h3 id="模型" tabindex="-1">模型 <a class="header-anchor" href="#模型" aria-label="Permalink to &quot;模型&quot;">​</a></h3><p>选择本任务实际调用的模型档位。</p><p><strong>Claude CLI 模型档位</strong>（由轻量到强力）：</p><table tabindex="0"><thead><tr><th>档位</th><th>对应角色</th></tr></thead><tbody><tr><td>Haiku</td><td>轻量任务</td></tr><tr><td>Sonnet</td><td>常规任务</td></tr><tr><td>Opus</td><td>复杂任务</td></tr><tr><td>Fable</td><td>专项档位（v0.6.5 起）</td></tr></tbody></table><p><strong>出厂默认：</strong> Opus</p><blockquote><p>各档位对应的具体模型版本由当前激活的<a href="/docs/settings/providers.html">模型供应商</a>决定。</p></blockquote><p><strong>Codex CLI 模型：</strong> 通过 <a href="/docs/settings/providers.html">模型供应商</a> 中的 Codex OAuth 或自定义供应商配置；未手动选择模型时，默认使用 <code>gpt-5.5</code>（界面原文）。</p><p><strong>OpenCode CLI 模型：</strong> OpenCode 没有原生 OAuth 档位，其模型下拉<strong>复用应用已配置的 OpenAI 兼容供应商</strong>（模型映射经配置注入 OpenCode，无需重复填写 API Key）。因此需先在 <a href="/docs/settings/providers.html">模型供应商</a> 中为某个供应商填好 OpenAI 接口地址与模型，再回到任务中选择该「供应商 / 模型」。</p><hr><h3 id="思考深度" tabindex="-1">思考深度 <a class="header-anchor" href="#思考深度" aria-label="Permalink to &quot;思考深度&quot;">​</a></h3><p>控制模型在回答前花多少算力进行内部推理（即&quot;扩展思考&quot;功能的深度）。</p><p><strong>Claude CLI 思考深度</strong>（由浅到深）：</p><table tabindex="0"><thead><tr><th>档位</th><th>界面原文</th></tr></thead><tbody><tr><td>低</td><td>low</td></tr><tr><td>中</td><td>medium</td></tr><tr><td>高</td><td>high</td></tr><tr><td>超高</td><td>xhigh</td></tr><tr><td>最高</td><td>max</td></tr><tr><td>极限</td><td>ultracode</td></tr></tbody></table><p><strong>Codex CLI 思考深度</strong>（由浅到深）：</p><table tabindex="0"><thead><tr><th>档位</th><th>界面原文</th></tr></thead><tbody><tr><td>极简</td><td>minimal</td></tr><tr><td>低</td><td>low</td></tr><tr><td>中</td><td>medium</td></tr><tr><td>高</td><td>high</td></tr><tr><td>超高</td><td>xhigh</td></tr></tbody></table><p><strong>OpenCode CLI 思考深度</strong>（由浅到深，v0.9.0 起）：</p><table tabindex="0"><thead><tr><th>档位（界面原文）</th><th>说明</th></tr></thead><tbody><tr><td><strong>default</strong></td><td>首档，不指定推理深度，使用所选模型的内置默认（同时保护不支持推理的模型）</td></tr><tr><td>minimal / low / medium / high / xhigh</td><td>由浅到深指定 OpenCode 的推理深度</td></tr></tbody></table><p><strong>出厂默认：</strong></p><ul><li>Claude CLI：max</li><li>Codex CLI：medium</li><li>OpenCode CLI：default（不指定，跟随模型内置默认）</li></ul><p>思考深度越高，回答质量通常越好，但耗时与 Token 消耗也相应增加。若希望加快响应，可手动调低档位。</p><hr><h3 id="执行授权" tabindex="-1">执行授权 <a class="header-anchor" href="#执行授权" aria-label="Permalink to &quot;执行授权&quot;">​</a></h3><p>控制 CLI 在执行文件操作、运行命令等行为时的自主程度。</p><p><strong>Claude CLI 授权模式</strong>（v0.9.0 起与 Claude CLI 的 <code>--permission-mode</code> 对齐为 6 档，界面显示原文）：</p><table tabindex="0"><thead><tr><th>模式（界面原文）</th><th>说明</th></tr></thead><tbody><tr><td><strong>default</strong></td><td>每次写文件、执行命令前均弹出权限卡片，等你确认后再执行</td></tr><tr><td><strong>plan</strong></td><td>先生成完整操作计划，确认后再执行</td></tr><tr><td><strong>acceptEdits</strong></td><td>文件编辑操作自动通过，其他操作仍需确认</td></tr><tr><td><strong>auto</strong></td><td>自动档（v0.9.0 新增）：放行裁决交回 Claude CLI 自身，由 CLI 决定哪些操作直接放行、哪些仍需询问</td></tr><tr><td><strong>dontAsk</strong></td><td>不询问档（v0.9.0 新增）：同样交由 Claude CLI 裁决，本模式下尽量不打断询问</td></tr><tr><td><strong>bypassPermissions</strong></td><td>所有操作自动通过，无需确认</td></tr></tbody></table><blockquote><p><code>auto</code> 与 <code>dontAsk</code> 是本版对齐 Claude CLI 新增的两档，应用不再代为自动放行，而是把 <code>--permission-mode</code> 透传给被拉起的 Claude CLI 由其裁决。</p></blockquote><p><strong>Codex CLI 授权模式：</strong></p><table tabindex="0"><thead><tr><th>档位（界面原文）</th><th>说明</th></tr></thead><tbody><tr><td><strong>只读</strong></td><td>仅允许读取文件，不执行写入或命令</td></tr><tr><td><strong>自动</strong></td><td>自动执行大多数操作，高风险操作询问确认</td></tr><tr><td><strong>完全访问</strong></td><td>所有操作自动通过，等同于 Claude 的 bypassPermissions</td></tr></tbody></table><p><strong>OpenCode CLI 授权档位</strong>（v0.9.0 起，界面显示原文）：</p><table tabindex="0"><thead><tr><th>档位（界面原文）</th><th>说明</th></tr></thead><tbody><tr><td><strong>auto</strong></td><td>自动执行文件编辑与命令，不逐条询问（默认档）</td></tr><tr><td><strong>ask</strong></td><td>每次改文件、执行命令前都弹出审批卡片，等你确认</td></tr></tbody></table><p><strong>出厂默认：</strong></p><ul><li>Claude CLI：完全自主（bypassPermissions）</li><li>Codex CLI：自动</li><li>OpenCode CLI：auto</li></ul><div class="warning custom-block"><p class="custom-block-title">出厂默认为完全自主</p><p>Claude CLI 的出厂默认即为&quot;完全自主&quot;——该模式与 Codex 的&quot;完全访问&quot;、OpenCode 的 <code>auto</code> 都会跳过逐条确认，CLI 可在无人值守情况下修改、删除文件或执行系统命令。若你希望逐步确认每个操作，请改为 <code>default</code> / <code>plan</code>（Claude）、&quot;只读&quot;（Codex）或 <code>ask</code>（OpenCode）。建议仅在受控环境（沙盒、CI）或你完全了解任务内容时使用完全自主模式。</p></div><hr><h2 id="与全局设置的关系" tabindex="-1">与全局设置的关系 <a class="header-anchor" href="#与全局设置的关系" aria-label="Permalink to &quot;与全局设置的关系&quot;">​</a></h2><p>任务级配置仅影响当前任务，不修改全局默认值。关系如下：</p><table tabindex="0"><thead><tr><th>配置层级</th><th>位置</th><th>作用范围</th></tr></thead><tbody><tr><td>CLI 可执行文件路径</td><td><a href="/docs/settings/general.html#cli-命令">常规设置 → CLI 命令</a></td><td>全局，所有任务共用</td></tr><tr><td>模型供应商 / API Key</td><td><a href="/docs/settings/providers.html">模型供应商</a></td><td>全局，决定可用的模型集合</td></tr><tr><td>模型 / 思考深度 / 授权</td><td>任务选择器栏</td><td>单任务，新建任务继承上次配置</td></tr></tbody></table><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/settings/providers.html">模型供应商</a> — 配置第三方 API 以解锁更多模型选择</li><li><a href="/docs/settings/dependencies.html">依赖管理</a> — 检测与安装 Claude CLI / Codex CLI / OpenCode CLI</li></ul>',58)])])}const u=d(s,[["render",n]]);export{g as __pageData,u as default};
